1	import { Injectable } from '@nestjs/common';
2	import { Cron } from '@nestjs/schedule';
3	import { InjectRepository } from '@nestjs/typeorm';
4	import { Repository, LessThan } from 'typeorm';
5	import { OrderEntity } from '../persistence/entities/order.entity';
6	import { PaymentEntity } from '../persistence/entities/payment.entity';
7	import { SeatReservationEntity } from '../persistence/entities/seat-reservation.entity';
8	import { HealthCheckEntity } from '../persistence/entities/health-check.entity';
9	import { NotificationService } from '../../core/application/use-cases/notification.service';
10	import { OrderStatus } from '@checc/shared/types/order.types';
11	import { NotificationType } from '@checc/shared/types/notification.types';
12	import { WinstonLogger } from '../logging/winston.logger';
13	
14	@Injectable()
15	export class NotificationSchedulerService {
16	  private readonly logger = new WinstonLogger();
17	
18	  constructor(
19	    @InjectRepository(OrderEntity)
20	    private readonly orderRepo: Repository<OrderEntity>,
21	    @InjectRepository(PaymentEntity)
22	    private readonly paymentRepo: Repository<PaymentEntity>,
23	    @InjectRepository(SeatReservationEntity)
24	    private readonly seatRepo: Repository<SeatReservationEntity>,
25	    @InjectRepository(HealthCheckEntity)
26	    private readonly healthCheckRepo: Repository<HealthCheckEntity>,
27	    private readonly notificationService: NotificationService,
28	  ) {}
29	
30	  @Cron('0 */30 * * * *') // Every 30 minutes
31	  async handleScheduledNotifications() {
32	    await this.checkDueSoonOrders();
33	    await this.checkOverdueBalances();
34	    await this.checkPickupReady();
35	    await this.checkComplianceBreaches();
36	  }
37	
38	  /** Notify patients whose orders are approaching auto-cancel (due soon). */
39	  private async checkDueSoonOrders() {
40	    const warningThreshold = new Date(Date.now() + 15 * 60 * 1000); // 15 min from now
41	
42	    const approachingOrders = await this.orderRepo.find({
43	      where: {
44	        status: OrderStatus.PENDING_PAYMENT,
45	        autoCancelAt: LessThan(warningThreshold),
46	      },
47	    });
48	
49	    for (const order of approachingOrders) {
50	      const canSend = await this.notificationService.canDeliver(
51	        order.patientId,
52	        order.id,
53	      );
54	
55	      if (canSend) {
56	        await this.notificationService.create({
57	          userId: order.patientId,
58	          type: NotificationType.DUE_DATE,
59	          title: 'Payment Due Soon',
60	          body: `Your order ${order.orderNumber} will be auto-canceled if not paid soon.`,
61	          referenceType: 'order',
62	          referenceId: order.id,
63	        });
64	
65	        this.logger.log(
66	          `Due-date notification sent for order ${order.orderNumber}`,
67	          'NotificationScheduler',
68	        );
69	      }
70	    }
71	  }
72	
73	  /** Notify patients with overdue balances (orders past auto-cancel that were canceled). */
74	  private async checkOverdueBalances() {
75	    const overdueOrders = await this.orderRepo.find({
76	      where: {
77	        status: OrderStatus.CANCELED,
78	      },
79	    });
80	
81	    for (const order of overdueOrders) {
82	      // Check if there's a partial payment recorded for this order
83	      const payments = await this.paymentRepo.find({
84	        where: { orderId: order.id },
85	      });
86	
87	      // Only notify if there were payment attempts (indicating the patient was engaged)
88	      if (payments.length > 0) {
89	        const canSend = await this.notificationService.canDeliver(
90	          order.patientId,
91	          `overdue-${order.id}`,
92	        );
93	
94	        if (canSend) {
95	          await this.notificationService.create({
96	            userId: order.patientId,
97	            type: NotificationType.OVERDUE_BALANCE,
98	            title: 'Overdue Balance',
99	            body: `Order ${order.orderNumber} was canceled due to non-payment. Please contact staff if you wish to re-enroll.`,
100	            referenceType: 'order',
101	            referenceId: order.id,
102	          });
103	
104	          this.logger.log(
105	            `Overdue balance notification sent for order ${order.orderNumber}`,
106	            'NotificationScheduler',
107	          );
108	        }
109	      }
110	    }
111	  }
112	
113	  /** Notify patients whose seat reservations are confirmed (hold available for pickup). */
114	  private async checkPickupReady() {
115	    const confirmedReservations = await this.seatRepo.find({
116	      where: { status: 'CONFIRMED' },
117	      relations: ['enrollment'],
118	    });
119	
120	    for (const reservation of confirmedReservations) {
121	      if (!reservation.enrollment) continue;
122	
123	      const canSend = await this.notificationService.canDeliver(
124	        reservation.enrollment.patientId,
125	        `pickup-${reservation.id}`,
126	      );
127	
128	      if (canSend) {
129	        await this.notificationService.create({
130	          userId: reservation.enrollment.patientId,
131	          type: NotificationType.PICKUP_READY,
132	          title: 'Service Ready',
133	          body: 'Your reserved service is confirmed and ready. Please visit the clinic at your scheduled time.',
134	          referenceType: 'seat_reservation',
135	          referenceId: reservation.id,
136	        });
137	
138	        this.logger.log(
139	          `Pickup-ready notification sent for reservation ${reservation.id}`,
140	          'NotificationScheduler',
141	        );
142	      }
143	    }
144	  }
145	
146	  /** Notify staff about health check compliance breaches (24h SLA exceeded). */
147	  private async checkComplianceBreaches() {
148	    const breachedChecks = await this.healthCheckRepo.find({
149	      where: { complianceBreach: true },
150	    });
151	
152	    for (const hc of breachedChecks) {
153	      const canSend = await this.notificationService.canDeliver(
154	        hc.createdBy,
155	        hc.id,
156	      );
157	
158	      if (canSend) {
159	        await this.notificationService.create({
160	          userId: hc.createdBy,
161	          type: NotificationType.COMPLIANCE_BREACH,
162	          title: 'Compliance Breach Detected',
163	          body: `Health check ${hc.id} has exceeded the 24-hour review SLA.`,
164	          referenceType: 'health_check',
165	          referenceId: hc.id,
166	        });
167	
168	        this.logger.log(
169	          `Compliance breach notification sent for health check ${hc.id}`,
170	          'NotificationScheduler',
171	        );
172	      }
173	    }
174	  }
175	}
