1	import { create } from 'zustand';
2	import type { UserDto, LoginResponse } from '@checc/shared/types/auth.types';
3	import { apiClient, ApiError } from '@/api/client';
4	import { generateFingerprint } from '@/utils/fingerprint';
5	import { tokenStore } from '@/utils/token-store';
6	import { offlineStorage } from '@/utils/offline-storage';
7	import { syncQueue } from '@/utils/sync-queue';
8	
9	interface AuthState {
10	  user: UserDto | null;
11	  isAuthenticated: boolean;
12	  isLoading: boolean;
13	  error: string | null;
14	  captchaRequired: boolean;
15	
16	  login: (username: string, password: string, captchaId?: string, captchaAnswer?: string) => Promise<void>;
17	  logout: () => void;
18	  refreshAuth: () => Promise<void>;
19	  clearError: () => void;
20	}
21	
22	export const useAuthStore = create<AuthState>((set) => ({
23	  user: null,
24	  isAuthenticated: tokenStore.hasToken(),
25	  isLoading: false,
26	  error: null,
27	  captchaRequired: false,
28	
29	  login: async (username: string, password: string, captchaId?: string, captchaAnswer?: string) => {
30	    set({ isLoading: true, error: null });
31	    try {
32	      // Generate fingerprint in memory if not already set
33	      if (!tokenStore.getFingerprint()) {
34	        const fp = await generateFingerprint();
35	        tokenStore.setFingerprint(fp);
36	      }
37	      const payload: Record<string, unknown> = {
38	        username,
39	        password,
40	        deviceFingerprint: tokenStore.getFingerprint() || undefined,
41	      };
42	      if (captchaId && captchaAnswer) {
43	        payload.captchaId = captchaId;
44	        payload.captchaAnswer = captchaAnswer;
45	      }
46	      const response = await apiClient.post<{ data: LoginResponse }>('/auth/login', payload);
47	      const loginData = response.data;
48	      tokenStore.setTokens(loginData.accessToken, loginData.refreshToken);
49	      tokenStore.setUserId(loginData.user.id);
50	      set({ user: loginData.user, isAuthenticated: true, isLoading: false, captchaRequired: false });
51	    } catch (err) {
52	      const message = err instanceof ApiError ? err.message : 'Login failed';
53	      const isCaptchaRequired = err instanceof ApiError && err.errorCode === 'AUTH_008';
54	      set({ error: message, isLoading: false, captchaRequired: isCaptchaRequired });
55	      throw err;
56	    }
57	  },
58	
59	  logout: () => {
60	    const userId = tokenStore.getUserId() || 'anonymous';
61	    tokenStore.clear();
62	    set({ user: null, isAuthenticated: false, error: null, captchaRequired: false });
63	
64	    // Async cleanup of IndexedDB offline data (best-effort)
65	    offlineStorage.clearForUser(userId).catch(() => {});
66	    syncQueue.clearForUser(userId).catch(() => {});
67	  },
68	
69	  refreshAuth: async () => {
70	    try {
71	      const response = await apiClient.get<{ data: { user: UserDto } }>('/auth/me');
72	      set({ user: response.data.user, isAuthenticated: true });
73	    } catch {
74	      tokenStore.clear();
75	      set({ user: null, isAuthenticated: false });
76	    }
77	  },
78	
79	  clearError: () => set({ error: null }),
80	}));
