1	import {
2	  Injectable,
3	  Inject,
4	  UnauthorizedException,
5	  ConflictException,
6	  ForbiddenException,
7	} from '@nestjs/common';
8	import { JwtService } from '@nestjs/jwt';
9	import { InjectRepository } from '@nestjs/typeorm';
10	import { Repository, MoreThan } from 'typeorm';
11	import * as bcrypt from 'bcrypt';
12	import { UserEntity } from '../../../infrastructure/persistence/entities/user.entity';
13	import { LoginAttemptEntity } from '../../../infrastructure/persistence/entities/login-attempt.entity';
14	import { IUserRepository, USER_REPOSITORY } from '../ports/user.repository.port';
15	import { CaptchaService } from '../../../infrastructure/security/captcha.service';
16	import { AnomalyDetectorService } from './anomaly-detector.service';
17	import { AUTH_LIMITS, CAPTCHA_LIMITS } from '@checc/shared/constants/limits';
18	import { ErrorCodes } from '@checc/shared/constants/error-codes';
19	import { WinstonLogger } from '../../../infrastructure/logging/winston.logger';
20	import type { TokenPayload } from '@checc/shared/types/auth.types';
21	import type { RegisterInput, LoginInput } from '@checc/shared/schemas/auth.schema';
22	import { UserRole } from '@checc/shared/constants/roles';
23	
24	@Injectable()
25	export class AuthService {
26	  private readonly logger = new WinstonLogger();
27	
28	  constructor(
29	    @Inject(USER_REPOSITORY)
30	    private readonly userRepo: IUserRepository,
31	    @InjectRepository(LoginAttemptEntity)
32	    private readonly loginAttemptRepo: Repository<LoginAttemptEntity>,
33	    private readonly jwtService: JwtService,
34	    private readonly captchaService: CaptchaService,
35	    private readonly anomalyDetector: AnomalyDetectorService,
36	  ) {}
37	
38	  async register(input: RegisterInput, ipAddress?: string) {
39	    const existingUsername = await this.userRepo.findByUsername(input.username);
40	    if (existingUsername) {
41	      throw new ConflictException({
42	        message: 'Username already taken',
43	        errorCode: ErrorCodes.USERNAME_TAKEN,
44	      });
45	    }
46	
47	    const existingEmail = await this.userRepo.findByEmail(input.email);
48	    if (existingEmail) {
49	      throw new ConflictException({
50	        message: 'Email already taken',
51	        errorCode: ErrorCodes.EMAIL_TAKEN,
52	      });
53	    }
54	
55	    const passwordHash = await bcrypt.hash(input.password, 12);
56	    const user = await this.userRepo.create({
57	      username: input.username,
58	      email: input.email,
59	      passwordHash,
60	      fullName: input.fullName,
61	      role: UserRole.PATIENT,
62	      canApproveRefunds: false,
63	      isActive: true,
64	    });
65	
66	    this.logger.log(`User registered: ${user.username} (${user.role})`, 'AuthService');
67	
68	    // Record registration event for IP-based anomaly tracking
69	    // Uses '__registration__' fingerprint to distinguish from login events
70	    if (ipAddress) {
71	      await this.recordLoginAttempt(user.id, ipAddress, '__registration__', true);
72	      this.anomalyDetector.checkBulkRegistration(ipAddress).catch(() => {});
73	    }
74	
75	    return this.buildUserDto(user);
76	  }
77	
78	  async login(input: LoginInput, ipAddress: string) {
79	    // Server-driven CAPTCHA escalation: require CAPTCHA after suspicious activity threshold
80	    const recentFailedWindow = new Date(Date.now() - AUTH_LIMITS.LOCKOUT_DURATION_MINUTES * 60 * 1000);
81	    const recentFailedFromIp = await this.loginAttemptRepo.count({
82	      where: {
83	        ipAddress,
84	        success: false,
85	        attemptedAt: MoreThan(recentFailedWindow),
86	      },
87	    });
88	
89	    const captchaRequired = recentFailedFromIp >= CAPTCHA_LIMITS.MAX_CONSECUTIVE_FAILURES;
90	
91	    if (captchaRequired && (!input.captchaId || !input.captchaAnswer)) {
92	      throw new ForbiddenException({
93	        message: 'CAPTCHA is required due to suspicious login activity',
94	        errorCode: ErrorCodes.CAPTCHA_REQUIRED,
95	      });
96	    }
97	
98	    // Validate CAPTCHA if provided (always validate when present, even if not required)
99	    if (input.captchaId && input.captchaAnswer) {
100	      const captchaValid = await this.captchaService.verify(input.captchaId, input.captchaAnswer);
101	      if (!captchaValid) {
102	        throw new UnauthorizedException({
103	          message: 'Invalid or expired CAPTCHA',
104	          errorCode: ErrorCodes.CAPTCHA_INVALID,
105	        });
106	      }
107	    }
108	
109	    const user = await this.userRepo.findByUsername(input.username);
110	
111	    if (!user) {
112	      await this.recordLoginAttempt(null, ipAddress, input.deviceFingerprint, false);
113	      throw new UnauthorizedException({
114	        message: 'Invalid username or password',
115	        errorCode: ErrorCodes.INVALID_CREDENTIALS,
116	      });
117	    }
118	
119	    // Check lockout
120	    if (user.lockedUntil && user.lockedUntil > new Date()) {
121	      throw new ForbiddenException({
122	        message: `Account locked until ${user.lockedUntil.toISOString()}`,
123	        errorCode: ErrorCodes.ACCOUNT_LOCKED,
124	      });
125	    }
126	
127	    // Verify password
128	    const valid = await bcrypt.compare(input.password, user.passwordHash);
129	    await this.recordLoginAttempt(user.id, ipAddress, input.deviceFingerprint, valid);
130	
131	    if (!valid) {
132	      await this.checkAndLockAccount(user);
133	      throw new UnauthorizedException({
134	        message: 'Invalid username or password',
135	        errorCode: ErrorCodes.INVALID_CREDENTIALS,
136	      });
137	    }
138	
139	    if (!user.isActive) {
140	      throw new ForbiddenException({
141	        message: 'Account is deactivated',
142	        errorCode: ErrorCodes.FORBIDDEN,
143	      });
144	    }
145	
146	    // Clear any lock on successful login
147	    if (user.lockedUntil) {
148	      await this.userRepo.update(user.id, { lockedUntil: null });
149	    }
150	
151	    const tokens = this.generateTokens(user);
152	    this.logger.log(`Login successful: ${user.username}`, 'AuthService');
153	
154	    return {
155	      ...tokens,
156	      user: this.buildUserDto(user),
157	    };
158	  }
159	
160	  async validateToken(payload: TokenPayload) {
161	    const user = await this.userRepo.findById(payload.sub);
162	    if (!user || !user.isActive) return null;
163	    return this.buildUserDto(user);
164	  }
165	
166	  async getMe(userId: string) {
167	    const user = await this.userRepo.findById(userId);
168	    if (!user) {
169	      throw new UnauthorizedException({
170	        message: 'User not found',
171	        errorCode: ErrorCodes.INVALID_CREDENTIALS,
172	      });
173	    }
174	    return { user: this.buildUserDto(user) };
175	  }
176	
177	  async verifyCredentials(username: string, password: string): Promise<UserEntity | null> {
178	    const user = await this.userRepo.findByUsername(username);
179	    if (!user) return null;
180	    if (!user.isActive) return null;
181	    if (user.lockedUntil && user.lockedUntil > new Date()) return null;
182	    const valid = await bcrypt.compare(password, user.passwordHash);
183	    return valid ? user : null;
184	  }
185	
186	  private async recordLoginAttempt(
187	    userId: string | null,
188	    ipAddress: string,
189	    deviceFingerprint: string | undefined,
190	    success: boolean,
191	  ) {
192	    const attempt = this.loginAttemptRepo.create({
193	      userId,
194	      ipAddress,
195	      deviceFingerprint: deviceFingerprint || null,
196	      success,
197	    });
198	    await this.loginAttemptRepo.save(attempt);
199	  }
200	
201	  private async checkAndLockAccount(user: UserEntity) {
202	    const windowStart = new Date(Date.now() - AUTH_LIMITS.LOCKOUT_DURATION_MINUTES * 60 * 1000);
203	    const recentFailed = await this.loginAttemptRepo.count({
204	      where: {
205	        userId: user.id,
206	        success: false,
207	        attemptedAt: MoreThan(windowStart),
208	      },
209	    });
210	
211	    if (recentFailed >= AUTH_LIMITS.MAX_LOGIN_ATTEMPTS) {
212	      const lockUntil = new Date(Date.now() + AUTH_LIMITS.LOCKOUT_DURATION_MINUTES * 60 * 1000);
213	      await this.userRepo.update(user.id, { lockedUntil: lockUntil });
214	      this.logger.warn(
215	        `Account locked: ${user.username} (${recentFailed} failed attempts)`,
216	        'AuthService',
217	      );
218	    }
219	  }
220	
221	  private generateTokens(user: UserEntity) {
222	    const payload: TokenPayload = {
223	      sub: user.id,
224	      username: user.username,
225	      role: user.role as UserRole,
226	      canApproveRefunds: user.canApproveRefunds,
227	    };
228	
229	    return {
230	      accessToken: this.jwtService.sign(payload),
231	      refreshToken: this.jwtService.sign(payload, {
232	        expiresIn: process.env.JWT_REFRESH_EXPIRES_IN || '7d',
233	      }),
234	    };
235	  }
236	
237	  private buildUserDto(user: UserEntity) {
238	    return {
239	      id: user.id,
240	      username: user.username,
241	      email: user.email,
242	      role: user.role as UserRole,
243	      fullName: user.fullName,
244	      canApproveRefunds: user.canApproveRefunds,
245	      isActive: user.isActive,
246	      createdAt: user.createdAt.toISOString(),
247	    };
248	  }
249	}
250	
