1	import { Injectable, UnauthorizedException } from '@nestjs/common';
2	import { PassportStrategy } from '@nestjs/passport';
3	import { ExtractJwt, Strategy } from 'passport-jwt';
4	import { AuthService } from '../../core/application/use-cases/auth.service';
5	import type { TokenPayload } from '@checc/shared/types/auth.types';
6	
7	@Injectable()
8	export class JwtStrategy extends PassportStrategy(Strategy) {
9	  constructor(private readonly authService: AuthService) {
10	    super({
11	      jwtFromRequest: ExtractJwt.fromAuthHeaderAsBearerToken(),
12	      ignoreExpiration: false,
13	      secretOrKey: (() => {
14	        const secret = process.env.JWT_SECRET;
15	        if (!secret && process.env.NODE_ENV === 'production') {
16	          throw new Error('JWT_SECRET environment variable must be set in production');
17	        }
18	        return secret || 'checc_jwt_secret_dev_only_change_in_prod';
19	      })(),
20	    });
21	  }
22	
23	  async validate(payload: TokenPayload) {
24	    const user = await this.authService.validateToken(payload);
25	    if (!user) {
26	      throw new UnauthorizedException();
27	    }
28	    return user;
29	  }
30	}
