4	import { LoginPage } from '@/pages/auth/LoginPage';
5	import { DashboardPage } from '@/pages/dashboard/DashboardPage';
6	import { EnrollmentListPage } from '@/pages/enrollment/EnrollmentListPage';
7	import { EnrollmentFormPage } from '@/pages/enrollment/EnrollmentFormPage';
8	import { EnrollmentDetailPage } from '@/pages/enrollment/EnrollmentDetailPage';
9	import { OrderHistoryPage } from '@/pages/order/OrderHistoryPage';
10	import { OrderDetailPage } from '@/pages/order/OrderDetailPage';
11	import { PaymentRecordPage } from '@/pages/payment/PaymentRecordPage';
12	import { PaymentHistoryPage } from '@/pages/payment/PaymentHistoryPage';
13	import { RefundPage } from '@/pages/payment/RefundPage';
