20	import { ArticleCreatePage } from '@/pages/content/ArticleCreatePage';
21	import { PricingRulesPage } from '@/pages/admin/PricingRulesPage';
22	import { RiskDashboardPage } from '@/pages/admin/RiskDashboardPage';
23	import { UserRole } from '@checc/shared/constants/roles';
24	
25	// Role matrix per business domain
26	const patientAndAbove = [UserRole.PATIENT, UserRole.STAFF, UserRole.ADMIN];
27	const staffAndAdmin = [UserRole.STAFF, UserRole.ADMIN];
28	const allClinical = [UserRole.PATIENT, UserRole.STAFF, UserRole.ADMIN, UserRole.REVIEWER];
29	
30	export const router = createBrowserRouter([
31	  { path: '/login', element: <LoginPage /> },
32	  {
33	    path: '/',
34	    element: <AppShell />,
35	    children: [
36	      { index: true, element: <DashboardPage /> },
37	
38	      // Enrollments — Patient, Staff, Admin
39	      { path: 'enrollments', element: <RoleGate allowedRoles={patientAndAbove}><EnrollmentListPage /></RoleGate> },
