2	  Injectable,
3	  CanActivate,
4	  ExecutionContext,
5	  HttpException,
6	  HttpStatus,
7	} from '@nestjs/common';
8	import { Reflector } from '@nestjs/core';
9	import { RATE_LIMIT_KEY } from '../decorators/rate-limit.decorator';
10	import { extractClientIp } from '../../infrastructure/security/ip-extractor';
11	import { RATE_LIMITS } from '@checc/shared/constants/limits';
12	import { ErrorCodes } from '@checc/shared/constants/error-codes';
13	
14	interface BucketEntry {
15	  timestamps: number[];
16	}
17	
18	@Injectable()
19	export class RateLimitGuard implements CanActivate {
20	  private readonly buckets = new Map<string, BucketEntry>();
21	
22	  constructor(private reflector: Reflector) {}
23	
24	  canActivate(context: ExecutionContext): boolean {
25	    if (process.env.RATE_LIMIT_DISABLED === 'true') return true;
26	
27	    const request = context.switchToHttp().getRequest();
28	
29	    // Get per-endpoint override or use defaults
30	    const rateLimitMeta = this.reflector.getAllAndOverride<
31	      { limit: number; windowSeconds: number } | undefined
32	    >(RATE_LIMIT_KEY, [context.getHandler(), context.getClass()]);
33	
34	    const limit = rateLimitMeta?.limit ?? RATE_LIMITS.DEFAULT_REQUESTS_PER_MINUTE;
35	    const windowSeconds = rateLimitMeta?.windowSeconds ?? RATE_LIMITS.DEFAULT_WINDOW_SECONDS;
36	
37	    // Per-action key: identity + HTTP method + route path
38	    const user = request.user;
39	    const identity = user?.id || extractClientIp(request);
40	    const action = `${request.method}:${request.route?.path || request.path || '/'}`;
41	    const key = `${identity}:${action}`;
42	
43	    const now = Date.now();
44	    const windowMs = windowSeconds * 1000;
45	
46	    let bucket = this.buckets.get(key);
47	    if (!bucket) {
48	      bucket = { timestamps: [] };
49	      this.buckets.set(key, bucket);
50	    }
51	
52	    // Remove timestamps outside window
53	    bucket.timestamps = bucket.timestamps.filter((ts) => now - ts < windowMs);
54	
55	    if (bucket.timestamps.length >= limit) {
56	      throw new HttpException(
57	        {
58	          message: 'Too many requests',
59	          errorCode: ErrorCodes.RATE_LIMITED,
60	        },
61	        HttpStatus.TOO_MANY_REQUESTS,
62	      );
63	    }
64	
65	    bucket.timestamps.push(now);
66	    return true;
67	  }
68	}
