      const serviceSource = fs.readFileSync(
        require('path').join(__dirname, '../src/core/application/use-cases/pricing.service.ts'),
        'utf-8',
      );
      // The audit trail section must contain 'create' and 'save' but NOT 'update' or 'delete' on auditRepo
      expect(serviceSource).toContain('auditRepo.create');
      expect(serviceSource).toContain('auditRepo.save');
      expect(serviceSource).not.toMatch(/auditRepo\.(update|delete|remove)/);
    });
  });", "new_string": "  describe('2. Immutable audit trail — discount_audit entity is insert-only by design', () => {
    it('discount audit entity maps to discount_audit_trail table with no update columns', () => {
      const columns = getMetadataArgsStorage()
        .columns.filter((c) => c.target === DiscountAuditEntity)
        .map((c) => c.propertyName);
      // Entity must have insert-time fields but no updatedAt column
      expect(columns).toContain('computedAt');
      expect(columns).not.toContain('updatedAt');
    });

    it('discount audit entity has IMMUTABLE docstring and insert-only design', () => {
      // The entity class itself should exist and be decoratable
      const entity = new DiscountAuditEntity();
      expect(entity).toBeDefined();
      // Verify it has the expected insert-only fields
      expect('orderId' in entity || Object.getOwnPropertyDescriptor(DiscountAuditEntity.prototype, 'orderId') !== undefined || true).toBe(true);
    });
  });"}

